using System.Text.Json;

namespace Azure.ResourceManager
{
    internal static class ResponseErrorAotConverter
    {
        internal static ResponseError Read(JsonElement element)
        {
            string code = null, message = null;
            if (element.TryGetProperty("code", out var cp))
                code = cp.GetString();
            if (element.TryGetProperty("message", out var mp))
                message = mp.GetString();
            return new ResponseError(code, message);
        }

        internal static void Write(Utf8JsonWriter writer, ResponseError value)
        {
            writer.WriteStartObject();
            if (value.Code != null)
            {
                writer.WriteString("code"u8, value.Code);
            }
            if (value.Message != null)
            {
                writer.WriteString("message"u8, value.Message);
            }
            writer.WriteEndObject();
        }
    }
}

